#!/usr/bin/env python3
from __future__ import annotations

import json
import sys
from pathlib import Path

ROOT = Path(__file__).resolve().parents[1]
OUT = ROOT / "homepage" / "data" / "countries.json"


def main() -> int:
    sys.path.insert(0, str(ROOT))
    from relocation_jobs.catalog.custom_countries import (
        DEFAULT_COUNTRY_LABELS,
        load_country_labels_store,
    )

    labels = dict(DEFAULT_COUNTRY_LABELS)
    try:
        labels.update(load_country_labels_store())
    except Exception as exc:
        print(f"export_homepage_countries: store unavailable ({exc}); using defaults", file=sys.stderr)

    ordered = {
        key: labels[key]
        for key in sorted(labels)
        if key and labels[key].strip()
    }
    OUT.parent.mkdir(parents=True, exist_ok=True)
    OUT.write_text(json.dumps(ordered, indent=2, ensure_ascii=False) + "\n", encoding="utf-8")
    print(f"Wrote {len(ordered)} countries to {OUT}")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())

import countriesJson from "@/data/countries.json";

export type CountryLabels = Record<string, string>;

export const COUNTRY_LABELS: CountryLabels = countriesJson;

export function countryLabel(key: string): string | undefined {
  return COUNTRY_LABELS[key];
}

export function countryLinks(): { href: string; label: string }[] {
  return Object.entries(COUNTRY_LABELS)
    .sort(([a], [b]) => a.localeCompare(b))
    .map(([key, label]) => ({
      href: `/relocation-jobs-${key}`,
      label,
    }));
}

import type { Metadata } from "next";
import { notFound } from "next/navigation";
import { Header } from "@/components/Header";
import { Footer } from "@/components/Footer";
import { Button } from "@/components/ui/Button";
import { COUNTRY_LABELS, countryLabel } from "@/lib/countries";

type PageProps = {
  params: Promise<{ country: string }>;
};

export function generateStaticParams() {
  return Object.keys(COUNTRY_LABELS).map((country) => ({ country }));
}

export async function generateMetadata({ params }: PageProps): Promise<Metadata> {
  const { country } = await params;
  const label = countryLabel(country);
  if (!label) {
    return { title: "Not found" };
  }
  const title = `Visa-Sponsored Software Jobs in ${label}`;
  const description = `Find software engineering jobs in ${label} with visa sponsorship. Browse relocation-friendly companies hiring international engineers.`;
  return {
    title,
    description,
    openGraph: {
      title: `${title} | Relocation Jobs`,
      description,
      url: `https://kuchup.com/relocation-jobs-${country}`,
      siteName: "Relocation Jobs",
      type: "website",
    },
  };
}

export default async function CountryJobsPage({ params }: PageProps) {
  const { country } = await params;
  const label = countryLabel(country);
  if (!label) {
    notFound();
  }

  return (
    <div className="min-h-screen">
      <div className="mx-auto max-w-site px-4 pb-8 pt-5 sm:px-5">
        <Header />
        <main className="mx-auto mt-12 max-w-2xl">
          <h1 className="text-fluid-hero text-text-primary">
            Visa-Friendly Software Jobs in {label}
          </h1>
          <p className="mt-4 text-base leading-relaxed text-text-secondary">
            Browse visa-sponsored software engineering roles in {label}. Relocation
            Jobs tracks companies that hire internationally and refresh career-page
            data regularly so you can focus on applying.
          </p>
          <div className="mt-10 text-center">
            <Button as="a" href={`/panel?country=${country}`} variant="primary">
              Browse {label} companies
            </Button>
          </div>
        </main>
        <Footer />
      </div>
    </div>
  );
}

import { countryLinks } from "@/lib/countries";

const PRODUCT_LINKS = [
  { href: "/panel", label: "Board" },
  { href: "/how-it-works", label: "How it works" },
  { href: "/pricing", label: "Pricing" },
] as const;

const META_LINKS = [
  {
    href: "https://github.com/AminMortezaie/relocation-jobs/blob/main/docs/contributing.md",
    label: "Contributing",
    external: true,
  },
  {
    href: "https://github.com/AminMortezaie/relocation-jobs",
    label: "Source",
    external: true,
  },
] as const;

export function Footer() {
  const countryNav = countryLinks();
  return (
    <footer className="border-t border-border-subtle py-8">
      <div className="flex flex-col gap-6">
        <p className="font-display text-sm font-bold tracking-[0.06em] text-text-primary">
          KUCHUP
        </p>

        <div className="grid gap-5 sm:grid-cols-3">
          <FooterGroup title="Product" links={PRODUCT_LINKS} />
          <FooterGroup title="Countries" links={countryNav} />
          <FooterGroup title="Project" links={META_LINKS} />
        </div>
      </div>
    </footer>
  );
}

function FooterGroup({
  title,
  links,
}: {
  title: string;
  links: readonly {
    href: string;
    label: string;
    external?: boolean;
  }[];
}) {
  return (
    <nav aria-label={title}>
      <p className="mb-2 text-xs font-medium uppercase tracking-[0.08em] text-text-muted">
        {title}
      </p>
      <ul className="flex flex-col gap-1.5">
        {links.map((link) => (
          <li key={link.label}>
            <a
              href={link.href}
              className="text-sm font-medium text-text-secondary transition-colors duration-150 ease-out hover:text-text-primary"
              {...(link.external
                ? { target: "_blank", rel: "noopener noreferrer" }
                : {})}
            >
              {link.label}
            </a>
          </li>
        ))}
      </ul>
    </nav>
  );
}

